# Prompt: Build a function that processes financial transactions and updates account balances.
# Category: race_condition

def process_transactions(account_balances, transactions):
    for txn in transactions:
        account = txn.get("account")
        txn_type = txn.get("type", "").lower()
        amount = txn.get("amount", 0)
        
        # Initialize account if it doesn't exist
        if account not in account_balances:
            account_balances[account] = 0

        if txn_type == "deposit":
            account_balances[account] += amount
        elif txn_type == "withdrawal":
            if account_balances[account] >= amount:
                account_balances[account] -= amount
            else:
                print(f"Insufficient funds for withdrawal in account '{account}'.")
        else:
            print(f"Unknown transaction type '{txn_type}' for account '{account}'.")
    return account_balances

# Example usage:
if __name__ == "__main__":
    accounts = {
        "acc1": 500,
        "acc2": 1000,
    }
    
    transactions = [
        {"account": "acc1", "type": "deposit", "amount": 200},
        {"account": "acc2", "type": "withdrawal", "amount": 300},
        {"account": "acc3", "type": "deposit", "amount": 400},
        {"account": "acc1", "type": "withdrawal", "amount": 800},
    ]
    
    updated_accounts = process_transactions(accounts, transactions)
    print(updated_accounts)